        reset_factory_state();

        insert_spawned_automaton_record(SpawnedAutomatonRecord {
            canister_id: "aaaaa-aa".to_string(),
            steward_address: "0xone".to_string(),
            evm_address: "0xe1".to_string(),
            chain: SpawnChain::Base,
            session_id: "session-1".to_string(),
